INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$20a15c15-4fac-4547-9cb6-1a1ff35eb939$tag$, $tag$2026010500170$tag$, $tag$. (5583993356164)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"05/01/2026 17:35:37"},{"role":"client","text":"🌟 Boa tarde .! Que alegria ter você aqui com a gente! 🙌","time":"05/01/2026 17:35:38"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"05/01/2026 17:35:42"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"05/01/2026 17:35:45"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"05/01/2026 17:35:49"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"05/01/2026 17:35:55"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"05/01/2026 17:36:01"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"05/01/2026 17:36:01"},{"role":"client","text":"Sim, concordo","time":"05/01/2026 17:36:13"},{"role":"client","text":"✅ Obrigado, .! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"05/01/2026 17:36:14"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"05/01/2026 17:36:18"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"05/01/2026 17:36:30"},{"role":"client","text":"Olá! .!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"05/01/2026 17:36:31"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"05/01/2026 17:36:34"},{"role":"client","text":"Falar com um atendente","time":"05/01/2026 17:36:45"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"05/01/2026 17:36:46"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 17:37:01"},{"role":"client","text":"Queria saber se usam a Nota do Enem para ingressar na faculdade","time":"05/01/2026 17:37:12"},{"role":"agent","text":"*Thayanne Sales:* Sim ","time":"05/01/2026 17:38:00","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Qual o curso que deseja informações?","time":"05/01/2026 17:38:08","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Teologia","time":"05/01/2026 17:38:20"},{"role":"agent","text":"*Thayanne Sales:* Temos a modalidade presencial e EAD, qual deseja?","time":"05/01/2026 17:39:46","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Presencial","time":"05/01/2026 17:40:28"},{"role":"agent","text":"*Thayanne Sales:*  A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"05/01/2026 17:44:08","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"05/01/2026 17:44:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação Presencial em Teologia fica R$ 549,56.\n\n🤩 Estamos com uma condição especial, *desconto de 30%* na pontualidade durante toda graduação, que fica apenas R$ 384,69.  *Usando o cupom de desconto: BOLSA30*\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da matrícula, e as demais mensalidades pagas no dia 10 dos meses subsequentes ao início das aulas.\n\n🌟 *Valor promocional:* (Semestralidade R$ 2.308,15).\n\n⚠ *Valor mensal está sujeito a mudança de acordo a data de matrícula:*\n \nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 384,69 = R$ 2.308,15\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 461,63 = R$ 2.308,15\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 577,03 = R$ 2.308,15\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"05/01/2026 17:44:22","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"05/01/2026 17:44:29","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\n., esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"07/01/2026 09:55:48"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"07/01/2026 09:55:49"},{"role":"client","text":"., Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"07/01/2026 10:10:51"}]$tag$, $tag$2026-01-05 17:35:37+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 7, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1bff23dc-dc34-445d-b9a5-f70a932d5361$tag$, $tag$2026010500187$tag$, $tag$Fred Belle (819042667077)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia! Eu conseguiria fazer esse curso estando no Japão?","time":"05/01/2026 20:26:22"},{"role":"client","text":"🌟 Boa noite Fred Belle! Que alegria ter você aqui com a gente! 🙌","time":"05/01/2026 20:26:23"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"05/01/2026 20:26:26"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"05/01/2026 20:26:30"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"05/01/2026 20:26:37"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"05/01/2026 20:26:47"},{"role":"client","text":"Olá! Fred Belle!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"05/01/2026 20:26:48"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"05/01/2026 20:26:52"},{"role":"client","text":"Saber sobre os cursos","time":"05/01/2026 20:27:06"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"05/01/2026 20:27:10"},{"role":"client","text":"Graduação","time":"05/01/2026 20:27:22"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"05/01/2026 20:27:25"},{"role":"client","text":"Teologia (EAD)","time":"05/01/2026 20:27:36"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"05/01/2026 20:27:37"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"05/01/2026 20:27:41"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"05/01/2026 20:28:31"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"05/01/2026 20:28:32"},{"role":"client","text":"Ok","time":"05/01/2026 20:28:55"},{"role":"client","text":"Queria saber se eu conseguiria fazer o curso aqui do Japão ?","time":"05/01/2026 20:36:49"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"06/01/2026 08:03:26"},{"role":"client","text":"Queria saber se posso fazer o curso de teologia mesmo estando no Japão?","time":"06/01/2026 08:08:04"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"06/01/2026 08:34:55","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Pode sim, 100% ead!","time":"06/01/2026 08:35:03","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Assim","time":"06/01/2026 08:35:17"},{"role":"client","text":"Poderia me passar quanto ficaria o curso?","time":"06/01/2026 08:35:42"},{"role":"agent","text":"*Karina Pimentel:* Claro!","time":"06/01/2026 08:37:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"06/01/2026 08:37:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"06/01/2026 08:37:46","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Até quando posso fazer a matrícula?","time":"06/01/2026 09:56:47"},{"role":"agent","text":"*Karina Pimentel:* Inicio das aulas será em Fevereiro, para manter esse valor acima seria até dia 31/01.","time":"06/01/2026 10:09:50","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nFred Belle, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"07/01/2026 09:06:02"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"07/01/2026 09:06:03"},{"role":"client","text":"5","time":"07/01/2026 09:11:44"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"07/01/2026 09:11:45"},{"role":"client","text":"2","time":"07/01/2026 09:12:07"},{"role":"client","text":"Fred Belle, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"07/01/2026 09:12:08"}]$tag$, $tag$2026-01-05 20:26:22+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_