INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$e3cede08-e8a5-4356-9d6f-b79a5604a9a8$tag$, $tag$2026010900084$tag$, $tag$𝓓𝓪𝓷𝓲 𝓟𝓮𝓻𝓮𝓼 👩🏼 (5532998204539)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá","time":"09/01/2026 12:45:33"},{"role":"client","text":"🌟 Boa tarde 𝓓𝓪𝓷𝓲 𝓟𝓮𝓻𝓮𝓼 👩🏼! Que alegria ter você aqui com a gente! 🙌","time":"09/01/2026 12:45:35"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/01/2026 12:45:39"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/01/2026 12:45:43"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/01/2026 12:45:52"},{"role":"client","text":"Valor da pós educação cristã Classica","time":"09/01/2026 12:46:00"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"09/01/2026 12:46:01"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/01/2026 12:46:02"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/01/2026 12:46:15"},{"role":"client","text":"Olá! 𝓓𝓪𝓷𝓲 𝓟𝓮𝓻𝓮𝓼 👩🏼!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/01/2026 12:46:16"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/01/2026 12:46:20"},{"role":"client","text":"Saber sobre os cursos","time":"09/01/2026 12:51:11"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"09/01/2026 12:51:15"},{"role":"client","text":"Pós-Graduação","time":"09/01/2026 12:51:35"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"09/01/2026 12:51:40"},{"role":"client","text":"Educação Cristã Clássica","time":"09/01/2026 12:52:01"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"09/01/2026 12:52:03"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"09/01/2026 12:52:06"},{"role":"client","text":"Nao consigo iniciar fevereiro","time":"09/01/2026 12:53:03"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"09/01/2026 12:53:04"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"09/01/2026 12:53:08"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"09/01/2026 12:53:12"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"09/01/2026 12:53:13"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"09/01/2026 13:09:48"},{"role":"client","text":"Oi","time":"09/01/2026 13:13:40"},{"role":"client","text":"Karine","time":"09/01/2026 13:13:42"},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"09/01/2026 13:19:48","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Tudo bem?","time":"09/01/2026 13:19:51","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Como podemos lhe ajudar?","time":"09/01/2026 13:19:58","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"client","text":"Bia tarde\nTudo joia.\nPreciso fazer  pós educação Cristã  clássica","time":"09/01/2026 13:23:04"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"09/01/2026 13:27:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"09/01/2026 13:27:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"09/01/2026 13:27:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"09/01/2026 13:27:33","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Karine so tem 20%? Esse valor nao fecha no meu orçamento","time":"09/01/2026 13:29:34"},{"role":"client","text":"Karine essa da propaganda  acabou","time":"09/01/2026 13:33:16"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69612dd5d401370f9d0b3177)","time":"09/01/2026 13:33:25"},{"role":"agent","text":"*Karina Pimentel:* A senhora viu aonde?","time":"09/01/2026 13:42:30","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Rolando pós  no Google","time":"09/01/2026 13:50:32"},{"role":"agent","text":"*Karina Pimentel:* Esse anuncio não está correto!","time":"09/01/2026 14:47:42","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* O curso tem 16 meses.","time":"09/01/2026 14:47:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"09/01/2026 14:48:08","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Fechando hoje eu consigo um desconto especial!","time":"09/01/2026 14:48:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Qual seria este desconto?","time":"09/01/2026 14:51:18"},{"role":"agent","text":"*Karina Pimentel:* 50%","time":"09/01/2026 15:58:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Mensalidades ficarão no valor de R$ 239,58.","time":"09/01/2026 15:58:42","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Karina preciso da autorização do meu esposo.\nComo seria forma de pagamento boleto ?","time":"09/01/2026 15:59:57"},{"role":"client","text":"Digital","time":"09/01/2026 15:59:58"},{"role":"agent","text":"*Karina Pimentel:* Boleto, Cartão ou Pix.","time":"09/01/2026 16:00:40","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Pix faria todo mês,certo?","time":"09/01/2026 16:01:19"},{"role":"client","text":"O que vc precisa de documentos pra eu providenciar","time":"09/01/2026 16:04:34"},{"role":"agent","text":"*Karina Pimentel:* Isso, ficará disponível na plataforma os boletos!","time":"09/01/2026 16:16:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ótimo","time":"09/01/2026 16:16:30"},{"role":"agent","text":"*Karina Pimentel:* 🎁 Cupom de Desconto ECC: *BOLSA50*\n\n📌 Realize sua matrícula no link: bit.ly/InscricaoPosECC2024\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"09/01/2026 16:16:31","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Blz","time":"09/01/2026 16:16:48"},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estou a disposição!","time":"09/01/2026 16:17:20","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Chegando em casa ,vou ligar para meu esposo irei fazer","time":"09/01/2026 16:26:52"},{"role":"agent","text":"*Karina Pimentel:* Perfeito!","time":"09/01/2026 16:33:13","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\n𝓓𝓪𝓷𝓲 𝓟𝓮𝓻𝓮𝓼 👩🏼, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 17:35:15"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"09/01/2026 17:35:16"},{"role":"client","text":"𝓓𝓪𝓷𝓲 𝓟𝓮𝓻𝓮𝓼 👩🏼, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"09/01/2026 17:50:17"}]$tag$, $tag$2026-01-09 12:45:33+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 19, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_c