INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2060dd57-7e18-48f3-a789-59d48c73b22d$tag$, $tag$2026011400067$tag$, $tag$Rodrigo Lima GonÃ§alves (5516982521099)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"14/01/2026 11:20:03"},{"role":"client","text":"🌟 Bom dia Rodrigo Lima GonÃ§alves! Que alegria ter você aqui com a gente! 🙌","time":"14/01/2026 11:20:04"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"14/01/2026 11:20:08"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"14/01/2026 11:20:13"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"14/01/2026 11:20:18"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"14/01/2026 11:20:24"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"14/01/2026 11:20:30"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"14/01/2026 11:20:31"},{"role":"client","text":"Sim, concordo","time":"14/01/2026 11:21:34"},{"role":"client","text":"✅ Obrigado, Rodrigo Lima GonÃ§alves! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"14/01/2026 11:21:36"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 11:21:40"},{"role":"client","text":"Fundação Cidade Viva","time":"14/01/2026 11:25:24"},{"role":"client","text":"Bom dia, Rodrigo Lima GonÃ§alves! 🙌 Obrigado(a) por entrar em contato com a Fundação Cidade Viva.","time":"14/01/2026 11:25:25"},{"role":"client","text":"Selecione a opção abaixo para o que deseja:","time":"14/01/2026 11:25:29"},{"role":"client","text":"Quero ajudar","time":"14/01/2026 11:25:43"},{"role":"client","text":"Ótimo, Rodrigo Lima GonÃ§alves! 😊 É uma alegria ter você com a gente nessa missão de ajudar!","time":"14/01/2026 11:25:44"},{"role":"client","text":"Por favor, selecione no menu abaixo a opção para nos contar como você deseja contribuir:","time":"14/01/2026 11:25:48"},{"role":"client","text":"Voltar ao menu anterior","time":"14/01/2026 11:26:04"},{"role":"client","text":"Selecione a opção abaixo para o que deseja:","time":"14/01/2026 11:26:09"},{"role":"client","text":"Voltar ao menu anterior","time":"14/01/2026 11:26:21"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 11:26:22"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 11:26:33"},{"role":"client","text":"Olá! Rodrigo Lima GonÃ§alves!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"14/01/2026 11:26:34"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"14/01/2026 11:26:38"},{"role":"client","text":"Saber sobre os cursos","time":"14/01/2026 11:26:52"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"14/01/2026 11:26:56"},{"role":"client","text":"Pós-Graduação","time":"14/01/2026 11:27:16"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"14/01/2026 11:27:20"},{"role":"client","text":"Liderança Cristã","time":"14/01/2026 11:27:39"},{"role":"client","text":"Lidere com sabedoria, integridade e propósito.\n 🧭 Curso voltado para líderes de igrejas, ministérios e organizações cristãs\n 🌍 Temas como discipulado, liderança servidora e gestão de equipes\n 📅 Ainda dá tempo de começar este semestre!\n","time":"14/01/2026 11:27:40"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"14/01/2026 11:27:44"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"14/01/2026 11:28:03"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"14/01/2026 11:28:04"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"14/01/2026 11:38:19"},{"role":"client","text":"Karina, gostaria de saber sobre valores do curso de liderança e se para pastores tem algum desconto.","time":"14/01/2026 11:46:13"},{"role":"client","text":"Também saber como é disponibilizado o material usado em cada matéria? PDF?","time":"14/01/2026 11:47:11"},{"role":"agent","text":"*Karina Pimentel:* \n *Pós-graduação em Liderança Cristã*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO E CARGA HORÁRIA\nO curso tem duração de 16 meses, com carga horária de 400h.\n\nDISCIPLINAS\nContamos com um total de 10 disciplinas.\n\nAULAS E AVALIAÇÕES\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas. As avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigatoriedade de TCC.","time":"14/01/2026 11:49:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Liderança Cristã está em 16 mensalidades de *R$ 359,37.*\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril.","time":"14/01/2026 11:50:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 70% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 107,81.\nVamos garantir a sua vaga? 😊","time":"14/01/2026 11:51:29","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Nossa o preço está bom mesmo!!! A forma de pagamento é somente no cartão? Tem o pagamento recorrente? Pergunto porque nesse mês as coisas apertam devido a tantos impostos e escola das filhas!!! Aí vou analisar o que posso estar fazendo!!","time":"14/01/2026 11:54:48"},{"role":"agent","text":"*Karina Pimentel:* Pix, boleto ou cartão?","time":"14/01/2026 11:57:56","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:*      Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"15/01/2026 11:31:19","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nRodrigo Lima GonÃ§alves, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 11:31:20"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"15/01/2026 11:31:21"},{"role":"client","text":"Rodrigo Lima GonÃ§alves, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"15/01/2026 11:46:21"}]$tag$, $tag$2026-01-14 11:20:03+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
