INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$48ac0f3a-24b6-4460-8d44-50017667f725$tag$, $tag$2026010200031$tag$, $tag$Ana Formiga (5583987061291)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Boa tarde !","time":"02/01/2026 12:49:30"},{"role":"client","text":"🌟 Boa tarde Ana Formiga! Que alegria ter você aqui com a gente! 🙌","time":"02/01/2026 12:49:31"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"02/01/2026 12:49:35"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"02/01/2026 12:49:38"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"02/01/2026 12:49:42"},{"role":"client","text":"Eu quero fazer a minha inscrição na faculdade de direito da cidade viva","time":"02/01/2026 12:49:48"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"02/01/2026 12:49:48"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"02/01/2026 12:49:49"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"02/01/2026 12:49:54"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"02/01/2026 12:49:55"},{"role":"client","text":"Sim, concordo","time":"02/01/2026 12:50:17"},{"role":"client","text":"✅ Obrigado, Ana Formiga! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"02/01/2026 12:50:18"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"02/01/2026 12:50:22"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"02/01/2026 12:50:41"},{"role":"client","text":"Olá! Ana Formiga!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"02/01/2026 12:50:42"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"02/01/2026 12:50:46"},{"role":"client","text":"Falar com um atendente","time":"02/01/2026 12:51:02"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"02/01/2026 12:51:02"},{"role":"client","text":"Gostaria de saber como fica o boleto de pagamento já com o desconto ? Terei de pagar uns três meses adiantado ou conforme semestre ?","time":"02/01/2026 12:51:57"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 14:20:17"},{"role":"client","text":"Boa tarde","time":"02/01/2026 15:12:02"},{"role":"client","text":"Eu gostaria de saber sobre como fica o desconto de 60 por cento a faculdade de direito","time":"02/01/2026 15:12:34"},{"role":"client","text":"E como ficam os boletos","time":"02/01/2026 15:12:43"},{"role":"client","text":"Se é por mês ou se tem que pagar o semestre todo ?","time":"02/01/2026 15:13:04"},{"role":"client","text":"Todo de uma vez","time":"02/01/2026 15:13:10"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"02/01/2026 15:28:00","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"02/01/2026 15:28:21","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* \n  A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"02/01/2026 15:28:43","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Mensalmente","time":"02/01/2026 15:29:06","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Essas 6 mensalidades é de 563 né isso ?","time":"02/01/2026 15:54:45"},{"role":"client","text":"O boleto já sai nesse valor","time":"02/01/2026 15:54:51"},{"role":"client","text":"?","time":"02/01/2026 15:55:02"},{"role":"client","text":"Ótimo","time":"02/01/2026 15:55:10"},{"role":"client","text":"Eu vou fazer","time":"02/01/2026 15:55:15"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/695814a7d6f2c842ef03f497)","time":"02/01/2026 15:55:35"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/695814d59d21cbc53f0546f3)","time":"02/01/2026 15:56:21"},{"role":"client","text":"Eu vou fazer sim","time":"02/01/2026 15:56:45"},{"role":"agent","text":"*Karina Pimentel:* Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08","time":"02/01/2026 16:16:52","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* Realizando os pagamentos até o dia 10 de todo mês, os descontos serão mantidos!","time":"02/01/2026 16:17:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Aumento somente anual, em média 6%.","time":"02/01/2026 16:17:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Certo","time":"02/01/2026 16:19:44"},{"role":"agent","text":"*Karina Pimentel:*  Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"02/01/2026 17:54:34","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nAna Formiga, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 17:54:36"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"02/01/2026 17:54:37"},{"role":"client","text":"Ana Formiga, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"02/01/2026 18:09:38"}]$tag$, $tag$2026-01-02 12:49:30+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 8, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commerc