INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$6bab5d1d-cd7b-4fbb-aa50-3c291a6dd5fd$tag$, $tag$2026010500018$tag$, $tag$Dilma (5511947727908)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"05/01/2026 09:00:44"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"05/01/2026 09:00:45"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"05/01/2026 09:00:46"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 09:31:31"},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"05/01/2026 09:31:49","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"05/01/2026 09:31:54","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom BOLSA10\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"05/01/2026 09:32:01","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"05/01/2026 09:32:06","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"oi","time":"05/01/2026 15:28:04"},{"role":"client","text":"eu já fiz a inscrição e a redação","time":"05/01/2026 15:28:15"},{"role":"client","text":"Qual o proximo passo","time":"05/01/2026 15:28:22"},{"role":"agent","text":"*Thayanne Sales:* Me envia seu nome completo ","time":"05/01/2026 15:41:45","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Que vou solicitar a correção","time":"05/01/2026 15:41:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Dilma Garcia Correia","time":"05/01/2026 16:36:37"},{"role":"agent","text":"*Thayanne Sales:* Agora é só ir no mesmo link que fez a inscrição, na parte \" já me inscrevi\", colocar o seu CPF e na senha é sua data de nascimento completo.\nIr em \"Visualização de contrato\", da o aceite e após isso vai abrir a forma de pagamento.","time":"05/01/2026 16:52:53","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ta bom","time":"05/01/2026 17:05:45"},{"role":"client","text":"o valor está 399,70","time":"05/01/2026 17:21:04"},{"role":"client","text":"não é 359,73","time":"05/01/2026 17:21:23"},{"role":"client","text":"eu esqueci de colocar bolsa10","time":"05/01/2026 17:22:43"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/695c1dd039e37d45780da38b)","time":"05/01/2026 17:23:44","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/695c1e22a4b28115d803e15e)","time":"05/01/2026 17:25:06"},{"role":"client","text":"Prontinho","time":"05/01/2026 17:25:26"},{"role":"client","text":"Obrigado","time":"05/01/2026 17:25:30"},{"role":"agent","text":"*Thayanne Sales:* Que maravilha!!","time":"05/01/2026 17:26:59","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Seja muito bem-vinda a Faculdade Internacional Cidade Viva ","time":"05/01/2026 17:27:12","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Agora é só aguardar o inicio das aulas em 02/02","time":"05/01/2026 17:27:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"05/01/2026 17:27:29","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"não","time":"05/01/2026 17:27:43"},{"role":"client","text":"obrigado","time":"05/01/2026 17:27:44"},{"role":"agent","text":"*Thayanne Sales:* Por nada! Deus abençoe e uma ótima semana.","time":"05/01/2026 17:28:06","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nDilma, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"05/01/2026 17:28:17"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"08/01/2026 17:25:46"},{"role":"client","text":"Sua sessão expirou!","time":"08/01/2026 17:27:47"}]$tag$, $tag$2026-01-05 09:00:44+00$tag$, FALSE, FALSE, 7, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 5, 2, 9, 13, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id