INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$cca482cf-88d7-4aa2-a003-9689321aa1b1$tag$, $tag$2026010400025$tag$, $tag$Gislaine Cristina Klein Klein (5549998000307)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Gestao Escolar e quero mais informações.","time":"04/01/2026 22:00:23"},{"role":"client","text":"🌟 Boa noite Gislaine Cristina Klein Klein! Que alegria ter você aqui com a gente! 🙌","time":"04/01/2026 22:00:24"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"04/01/2026 22:00:29"},{"role":"client","text":"Quando começa as aulas?","time":"04/01/2026 22:00:31"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"04/01/2026 22:00:32"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"04/01/2026 22:00:39"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"04/01/2026 22:01:41"},{"role":"client","text":"Olá! Gislaine Cristina Klein Klein!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"04/01/2026 22:01:42"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"04/01/2026 22:01:46"},{"role":"client","text":"Saber sobre os cursos","time":"04/01/2026 22:01:59"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"04/01/2026 22:02:03"},{"role":"client","text":"Pós-Graduação","time":"04/01/2026 22:02:10"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"04/01/2026 22:02:14"},{"role":"client","text":"Psicopedagogia","time":"04/01/2026 22:02:30"},{"role":"client","text":"Essa pós é ideal para quem deseja compreender e intervir nos processos de aprendizagem com uma abordagem ética, cristã e prática.\n\n 🧠 100% online, estude no seu ritmo\n 🎓 Professores experientes e materiais atualizados\n 📅 Aulas iniciam em agosto\n 💰 Condição promocional especial para novas matrículas","time":"04/01/2026 22:02:31"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"04/01/2026 22:02:35"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"04/01/2026 22:03:52"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"04/01/2026 22:03:53"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"04/01/2026 22:03:53"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 10:58:50"},{"role":"agent","text":"*Thayanne Sales:* PÓS-GRADUAÇÃO EM GESTÃO ESCOLAR.\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n480 horas + 2 disciplinas optativas\n\nDISCIPLINAS\nDisciplinas: 12 + 2 disciplinas optativas\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"05/01/2026 10:59:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Disciplinas da Pós em Gestão Escolar*\n\nBASE: PEDAGÓGICA\n\n1-Educação e Cosmovisão Cristã - Prof. Ms. Thiago\nDutra\n2-Fundamentos Filosóficos e\nMetodológicos da Educação\nCristã - Prof. Ms. Thiago Dutra\n3-Introdução à Educação Cristã Clássica - Prof. Ms. ThiagoDutra\n4-Apoio Psicopedagógico,\nAprendizagem mediada e\nInclusão - Prof. Ms.Fabiana Sousa\n5-Disciplina Virtuosa (50%\ngravada) - Prof. Esp. Filipe Asafe/ Profª. Letícia Ruiz Alves\n\nBASE: PLANEJAMENTO E LEGISLAÇÃO\n\n6-Planejamento Estratégico:Missão, Visão e Valores.Definição das estratégias eobjetivos estratégicos\nPlanos de ação e indicadores - Prof. Dr.Josemar Bandeira\n7-Estrutura Básica do Sistema Educacional Brasileiro - Prof. Esp.Edmilson Almeida\n8-Projeto Político Pedagógico e Regimento Interno - Prof. Ms. Thiago Dutra\n\nBASE: GESTÃO ESCOLAR\n\n9-Gestão de Pessoas e Cultura Organizacional - Profª. Esp.Patrícia Queiroz\n10-Gestão por Processos 40 Prof. Ms. Renato Assis\n11-Gestão de Marketing 40 Prof. Dr.Josemar Bandeira\n12-Gestão Financeira 40 Prof. Ms. Renato Assis\n\n- Módulo optativo: Formação para Coordenadores Pedagógicos\n- Módulo optativo: Incubadora de Novas Escolas","time":"05/01/2026 10:59:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Gestão Escolar está em 16 mensalidades de *R$ 479,16*. Esse mês esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026.\n\n\n🎁 Cupom de Desconto da Pós em Gestão Escolar: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_24\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"05/01/2026 10:59:30","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Não quero de gestão escolar, quero de Psicopedagogia 😉","time":"05/01/2026 11:00:13"},{"role":"agent","text":"*Thayanne Sales:* *PÓS-GRADUAÇÃO EM PSICOPEDAGOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 18 meses.\n\nCARGA HORÁRIA\n630 horas\n\nDISCIPLINAS\n12 disciplinas obrigatórias e 1  disciplina optativa\n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova d","time":"05/01/2026 11:01:16","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* NÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"05/01/2026 11:01:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* *Disciplinas da Pós em Psicopedagogia*\n\nBASE: FILOSÓFICA TEOLÓGICA\n\n1-Introdução à Cosmovisão Cristã - Dr. Bruno Ribeiro\n2-Fundamentos Filosóficos e Metodológicos de uma Pedagogia Cristã - Me. Thiago Dutra\n3-Introdução à Educação Cristã Clássica - Me. Thiago Dutra\n\nBASE: PSICOPEDAGOGIA E DESENVOLVIMENTO\n\n4-Fundamentos da Psicopedagogia - Ma. Luciana Siqueira\n5-Alfabetização Fônica - Esp. Finlândia de Oliveira das Chagas\n6-Aprendizagem da Matemática - Esp. Úrsula Keyla\n7-Desenvolvimento Cognitivo e Neurociência - Alessandra Schneider\n8-Síndromes, Transtornos e Dificuldades de Aprendizagem - Ma. Fabiana Josefa Sousa\n\nBASE: Avaliação, Diagnóstico e Mediação Psicopedagógica\n\n9-Teoria da Experiência de Aprendizagem Mediada em Feuerstein - Me. David Sasson/ Marcia Macionk\n10-Avaliação e Intervenção Psicopedagógica - Dra. Edith Rubstein\n11-Âmbitos de atuação do Psicopedagogo e Educação Formal - Esp. Karine Canani\n12-Temas contemporâneos em psicopedagogia:\n1- Inclusão e atuação do Psicopedagogo - Dra. Cristiane Souza;\n2- Uso das tecnologias e asimplicações para aprendizagem - Esp. Letícia Ruiz\n3- Altas Habilidades e Superdotação - Vera Pereira\n4- Direito Educacional Aplicado - Esp. Vladimir Miná\n5- Disciplina baseada em Virtudes -  Esp. LetíciaRuiz\n\n13 Seminário de práticas Psicopedagógicas - Ma. Fabiana Josefa Sousa/ Ma. Luciana Siqueira","time":"05/01/2026 11:01:32","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Psicopedagogia  está em 18 mensalidades de *R$ 479,16*. Esse mês esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.\n\n\n🎁 Cupom de Desconto da Pós em Psicopedagogia: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_26\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"05/01/2026 11:01:40","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Estou aguardando a minha colação de grau, sou formada em Direito mas concluí Pedagogia em dezembro. Tem problema em realizar a matrícula sem a certificação? Posso enviar uma declaração?","time":"05/01/2026 11:05:57"},{"role":"agent","text":"*Thayanne Sales:* Não tem problema","time":"05/01/2026 11:07:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Você tem até o fim da pós para nos enviar o diploma da graduação ","time":"05/01/2026 11:07:38","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ótimo","time":"05/01/2026 11:08:26"},{"role":"client","text":"Vocês tem algum outro curso para indicar dentro do tema Alfabetização e Letramento?","time":"05/01/2026 11:08:56"},{"role":"client","text":"Algo mais profundo sobre o assunto","time":"05/01/2026 11:13:24"},{"role":"agent","text":"*Thayanne Sales:* Aqui estão os cursos disponíveis:\n\nGraduações\n\n* Direito (Presencial)\n* Teologia (presencial e EAD)\n\nPós-Graduações\n\n* Educação Cristã Clássica (EAD) - 16 meses\n* Novo Testamento (EAD) - 16 meses\n* Liderança Cristã (EAD) - 16 meses\n* Ciência Política (EAD) - 16 meses\n* Missiologia Urbana (EAD) - 16 meses\n* Teologia Sistemática (EAD) - 16 meses\n* Gestão Escolar (EAD) - 16 meses\n* Psicopedagogia (EAD) - 18 meses\n*Psicoteologia (EAD) - 16 meses","time":"05/01/2026 11:39:04","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Olá Bom dia! Tudo bom?\n\nQual o curso que deseja informações?","time":"06/01/2026 08:15:38","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nGislaine Cristina Klein Klein, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"06/01/2026 13:20:44"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"06/01/2026 13:20:45"},{"role":"client","text":"Gislaine Cristina Klein Klein, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"06/01/2026 13:35:46"}]$tag$, $tag$2026-01-04 22:00:23+00$tag$, FALSE, FALSE, 8, $tag$2026-03-01 16:46:57.607947+00$tag$, 9, 10, 10, 2, 9, 11, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$6dc611bf-1350-4dc2-a4af-88b914b49bab$tag$, $tag$2026010400029$tag$, $tag$Fábio Rocha (5535988179500)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Missiologia Urbana e quero mais informações.","time":"04/01/2026 22:37:52"},{"role":"client","text":"🌟 Boa noite Fábio Rocha! Que alegria ter você aqui com a gente! 🙌","time":"04/01/2026 22:37:53"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"04/01/2026 22:37:57"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"04/01/2026 22:38:01"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"04/01/2026 22:38:05"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"04/01/2026 22:38:11"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"04/01/2026 22:38:16"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"04/01/2026 22:38:18"},{"role":"client","text":"Sim, concordo","time":"04/01/2026 22:38:28"},{"role":"client","text":"✅ Obrigado, Fábio Rocha! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"04/01/2026 22:38:29"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"04/01/2026 22:38:33"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"04/01/2026 22:38:46"},{"role":"client","text":"Olá! Fábio Rocha!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"04/01/2026 22:38:47"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"04/01/2026 22:38:51"},{"role":"client","text":"Saber sobre os cursos","time":"04/01/2026 22:40:25"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"04/01/2026 22:40:29"},{"role":"client","text":"Pós-Graduação","time":"04/01/2026 22:42:26"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"04/01/2026 22:42:30"},{"role":"client","text":"Missiologia Urbana","time":"04/01/2026 22:43:43"},{"role":"client","text":"Aprenda a ler, servir e transformar as cidades com o Evangelho.\n 🏙️ Curso inovador com foco em missão no contexto urbano\n 🎯 Ideal para plantadores de igrejas, missionários e líderes urbanos\n 🕊️ Aulas online com mentoria prática\n","time":"04/01/2026 22:43:44"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"04/01/2026 22:43:48"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"04/01/2026 22:44:00"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"04/01/2026 22:44:01"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"04/01/2026 22:44:02"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 09:56:25"},{"role":"agent","text":"*Thayanne Sales:* *Pós-Graduação em Missiologia Urbana*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 360 h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n*****************\n  *Missiologia Urbana* - Disciplinas do Curso:\n\nESPIRITUALIDADE MISSIONAL E CULTURA\n1 Teologia e Prática da Espiritualidade (Dr. Valdir Steuernagel e Dr. Tom White)\n2 Teologia da Missão Urbana (Dr. Sérgio Lyra e Dr. Mac Pier)\n3 Contextualização do Evangelho e da Cultura (Miss. Leandro Silva)\n\nMISSÃO E INTEGRALIDADE\n4 Missão Integral (Dr Chris Wright e Miss. Leandro Silva)\n5 Etnografia dos Grupos Urbanos (Dr Mark Matlock e Esp. Renildo Diniz)\n6 Eclesiologia Missional (Ms Valtenci Oliveira)\n\nMISSIONALIDADE, TRANSFORMAÇÃO E CIDADANIA\n7 Fé, Política e Cidadania (Davi Lago)\n8 Justiça, Pobreza e Transformação (Dr N. T. Wright e Ms Bebeto Araújo)\n9 Igreja e Meio-Ambiente (Esp. José Marcos da Silva)\n\nGESTÃO MISSIONAL\n10 Liderança Missional Urbana (Dr. Sérgio Queiroz)\n11 Captação de Recursos para Projetos Sociais (Ms Rafael Bandeira)\n12 Elaboração de Projetos Missionais Urbanos (Esp. Lisania Pereira)\n\nObs: Professores sujeitos a alterações. ","time":"05/01/2026 09:56:47","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Missiologia Urbana está em 16 mensalidades de *R$ 359,37*. Esse mês esta com condições especiais com esta com 50% de desconto e as mensalidades ficam por R$ 179,68\n\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril/2026.\n \n\n🎁 Cupom de Desconto Missiologia: *BOLSA50*\n\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_20\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"05/01/2026 09:56:56","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"vc tem a ementa das disciplinas?","time":"05/01/2026 10:26:59"},{"role":"agent","text":"*Thayanne Sales:* *Ementa da Pós em Missiologia Urbana*\n\n*Teologia e Prática da Espiritualidade*\nEmenta: Esta disciplina visa apresentar os fundamentos teológicos e\npráticos de uma espiritualidade cristã robusta e integral, que se constitui a\nbase para um ministério urbano fiel, frutífero e resiliente. A partir de uma\nanálise das escrituras sagradas, tanto do Antigo quanto do Novo testamento,\nbem como dos clássicos da espiritualidade cristã, serão abordados temas\ncomo: fundamentos bíblicos: a espiritualidade cristã e o evangelho do reino;\nmodelos históricos para uma espiritualidade bíblica e transformadora;\ndisciplinas espirituais e resiliência no ministério; caminhos práticos para\nespiritualidade e missão no século XXI.\n\n*Teologia da missão urbana*\nEmenta: Esta disciplina visa apresentar os fundamentos para uma teologia\nbíblica da missão urbana, tendo como base os textos do Antigo e do Novo\nTestamento, bem como recursos metodológicos para catalisar processos de\nimpacto coletivo frente aos desafios que os cristãos enfrentam nas cidades\ncontemporâneas. A partir de uma análise bíblica e teológica, serão\nabordados temas como: Missão urbana no contexto do Antigo e do Novo\nTestamento; O chamado para a cidade; O evangelho para o contexto\nurbano; Estabelecendo parcerias de colaboração na cidade.\n\n*Contextualização do evangelho e da cultura*\nEmenta: Esta disciplina visa analisar as bases bíblicas para a\ncontextualização equilibrada, visando prover instrumental teológico e prático\npara contextualizar o evangelho de modo a desafiar a cultura urbana,\nabordando temas como: o que é contextualização e como ela pode ser\ndesenvolvida de forma intencional, equilibrada, pastoral, bíblica e ativa;\ncosmovisão cristã e engajamento cultural na cidade contemporânea; o\nevangelho e os desafios da cultura urbana.\n\n*Missão integral da Igreja*\nEmenta: Esta disciplina visa apresentar os fundamentos da integralidade da\nmissão, que visa levar o evangelho todo para a pessoa toda e para todas as\npessoas através da ação missional de toda a igreja. A partir de uma análise\nbíblica, teológica e histórica, serão abordados temas como: a missão de\nDeus como paradigma para a igreja; o modelo missional de Jesus; o legado\nhistórico da igreja como agência de transformação; as cinco marcas da\nmissão; as ênfases e os conceitos-chave dos dois principais documentos\nmissiológicos do último século, o Pacto de Lausanne e o Compromisso da\nCidade do Cabo; cosmovisão cristã e transformação integral; características\nde uma igreja local que cumpre a missão em sua integralidade; o\ndesenvolvimento de uma filosofia de ministério missional.\n\n*Etnografia dos grupos urbanos*\nEmenta: Esta disciplina visa apresentar os conceitos básicos e ferramental\nprático da etnografia urbana para a missão da igreja hoje. A partir do recurso\na uma variedade de metodologias e técnicas de pesquisa, partilhadas por\ndiversas áreas do conhecimento, tais como a sociologia, a antropologia, a\nhistória, a geografia, a arquitetura, o urbanismo, a psicologia, a teologia,\nentre outras, serão abordados temas como: Fundamentos bíblicos para a\npesquisa e análise da realidade urbana; Etnografia urbana e sua\naplicabilidade na missão da igreja; Produção e análise de dados\netnográficos; Metodologias para diagnóstico da cidade e dos grupos\nurbanos.\n\n*Eclesiologia missional*\nEmenta: Esta disciplina visa refletir sobre a natureza missional e a\nidentidade da igreja, como cooperadora da missão de Deus em sua\ncomunidade e a partir dela. Por meio de uma perspectiva bíblica, teológica e\nprática, serão abordados temas como: a igreja missional no Antigo e Novo\nTestamento; Plantação e revitalização de igrejas; transições para o ministério\nmissional; crescimento integral da igreja; aspectos fundamentais de uma\nigreja missional hoje.\n\n*Fé, Política e Cidadania*\nEmenta: Esta disciplina visa apresentar os conceitos bíblicos e as práticas\nde educação política, políticas públicas, exercício da cidadania, e\ntransformação social, bem como as suas inter-relações e implicações para a\natuação dos cristãos no contexto urbano. A partir de uma perspectiva\nintegral e missional solidamente enraizada em uma robusta cosmovisão\ncristã, serão abordados temas como: Fé, política e cidadania no Antigo e\nNovo Testamento; Fé, política e cidadania na história da igreja; o que é\neducação política e qual a sua importância para a formação do cidadão; o\nque são políticas públicas e como elas se relacionam com os direitos\nhumanos e sociais; o que é exercício da cidadania e quais os seus direitos e\ndeveres; o que é advocacy e qual seu papel na missão da igreja na polis; fé,\nrazão e diálogo: a relação entre cidadania e discipulado; o que é uma visão\nde transformação social e quais os seus fundamentos éticos e teológicos.\n\n*Justiça, Pobreza e Transformação*\nEmenta: Esta disciplina visa refletir, por meio de uma abordagem bíblica,\nteológica e prática, sobre o grande desafio que representa o crescente\nquadro de pobreza nas comunidades periféricas urbanas, buscando oferecer\nrecursos metodológicos e boas práticas para o plantio e aprimoramento de\nministérios de justiça e transformação nestes contextos. A partir de um olhar\ninterdisciplinar enraizado na cosmovisão bíblica, buscaremos compreender a\npobreza e as respostas bíblicas que são demandadas dos cristãos frente a\nela; Qual a relação entre discipulado e justiça; como a missão cristã se\nconecta com o enfrentamento aos desafios econômicos das áreas\nsocialmente vulneráveis; quais as abordagens bíblicas e metodológicas para\na transformação de áreas empobrecidas; como responder de forma\nequilibrada e efetiva aos desafios que se apresentam para o testemunho do\nevangelho e a diaconia cristã nos contextos de vulnerabilidade social.\n\n*Igreja e meio ambiente*\nEmenta: Esta disciplina visa apresentar o chamado bíblico para o cuidado\nda criação, bem como os princípios e as práticas que possibilitem a igreja\nlocal desenvolver iniciativas de ação socioambiental como parte da sua ação\nmissional na cidade. Por meio de uma análise teológica e prática,\nabordaremos temas como: teologia bíblica da criação; o cuidado com a\ncriação de Deus como parte da missão; elaboração de projetos e ações\nsocioambientais a partir da igreja local; os desafios ambientais urbanos e a\nresposta da igreja.\n\n*Liderança missional urbana*\nEmenta: Esta disciplina visa apresentar os princípios e as práticas de\nliderança cristã em uma perspectiva missional para o contexto urbano, bem\ncomo os desafios e as oportunidades que se apresentam para os cristãos\nque exercem ou pretendem exercer um papel de liderança na mobilização\nda igreja para alcançar e servir a cidade. A partir de uma perspectiva bíblica,\nhistórica e ética, serão abordados temas como: o que é liderança missional e\nquais as suas características, valores e responsabilidades; quais as marcas\ndas igrejas que transformam o Brasil e qual o papel da liderança cristã em\nsua implementação nos âmbitos locais; quais os desafios que os líderes\ncristãos enfrentam e quais as oportunidades em assumir uma abordagem\nmissional, equipando e mobilizando outros para o cumprimento da missão\nna comunidade.\n\n*Captação de Recursos para Projetos Missionais*\nEmenta: A captação de recursos é um dos grandes desafios do ministério\nurbano. Nesta disciplina, buscaremos lançar um olhar bíblico, teológico e\nmetodológico sobre este tema fundamental, abordando o perfil do captador\nde recursos, o ciclo organizacional da captação de recursos, a mordomia\ncristã como elemento essencial na mobilização de fundos, a contribuição\ncristã como expressão da graça de Deus, o desenvolvimento de um plano de\ncaptação de recursos, prestação de contas e o cultivo da sustentabilidade de\nprojetos e organizações missionais.\n\n*Elaboração de Projetos Missionais Urbanos*\nEmenta: A partir de um olhar bíblico, prático e metodológico, esta disciplina\nabordará o desenvolvimento de projetos missionais que respondam aos\ndesafios das cidades e suas inúmeras comunidades, abordando temas\ncomo: Fundamentos bíblicos para elaboração de projetos, contexto das\nfavelas brasileiras, diagnóstico e propostas metodológicas de transformação\n(o modelo das favelas 3D, bancos comunitários, fundamentos do\nempreendedorismo social, etc), Gestão e planejamento - Ciclo de projetos,\nMetodologia para o desenvolvimento de projetos: Ferramentas e modelos\npráticos, comunicando o projeto. O(a) aluno(a) escreverá uma proposta de\nprojeto que responda a um desafio específico da sua cidade, tendo como\nbase a cosmovisão cristã, e as ferramentas ofertadas nesta disciplina, e ao\nlongo do curso.","time":"05/01/2026 10:32:22","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Ementa da Pós em Missiologia Urbana*\n\n*Teologia e Prática da Espiritualidade*\nEmenta: Esta disciplina visa apresentar os fundamentos teológicos e\npráticos de uma espiritualidade cristã robusta e integral, que se constitui a\nbase para um ministério urbano fiel, frutífero e resiliente. A partir de uma\nanálise das escrituras sagradas, tanto do Antigo quanto do Novo testamento,\nbem como dos clássicos da espiritualidade cristã, serão abordados temas\ncomo: fundamentos bíblicos: a espiritualidade cristã e o evangelho do reino;\nmodelos históricos para uma espiritualidade bíblica e transformadora;\ndisciplinas espirituais e resiliência no ministério; caminhos práticos para\nespiritualidade e missão no século XXI.\n\n*Teologia da missão urbana*\nEmenta: Esta disciplina visa apresentar os fundamentos para uma teologia\nbíblica da missão urbana, tendo como base os textos do Antigo e do Novo\nTestamento, bem como recursos metodológicos para catalisar processos de\nimpacto coletivo frente aos desafios que os cristãos enfrentam nas cidades\ncontemporâneas. A partir de uma análise bíblica e teológica, serão\nabordados temas como: Missão urbana no contexto do Antigo e do Novo\nTestamento; O chamado para a cidade; O evangelho para o contexto\nurbano; Estabelecendo parcerias de colaboração na cidade.\n\n*Contextualização do evangelho e da cultura*\nEmenta: Esta disciplina visa analisar as bases bíblicas para a\ncontextualização equilibrada, visando prover instrumental teológico e prático\npara conte