INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$3f10e39e-3b52-404e-80dc-b3ae6e6c3e96$tag$, $tag$2026010500031$tag$, $tag$Regiane (5511995895799)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Educacao Crista Classica e quero mais informações.","time":"05/01/2026 09:42:17"},{"role":"client","text":"🌟 Bom dia Regiane! Que alegria ter você aqui com a gente! 🙌","time":"05/01/2026 09:42:18"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"05/01/2026 09:42:22"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"05/01/2026 09:42:26"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"05/01/2026 09:42:29"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"05/01/2026 09:42:36"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"05/01/2026 09:42:42"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"05/01/2026 09:42:43"},{"role":"client","text":"Sim, concordo","time":"05/01/2026 09:43:33"},{"role":"client","text":"✅ Obrigado, Regiane! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"05/01/2026 09:43:34"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"05/01/2026 09:43:38"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"05/01/2026 09:44:00"},{"role":"client","text":"Olá! Regiane!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"05/01/2026 09:44:01"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"05/01/2026 09:44:04"},{"role":"client","text":"Saber sobre os cursos","time":"05/01/2026 09:44:18"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"05/01/2026 09:44:22"},{"role":"client","text":"Pós-Graduação","time":"05/01/2026 09:44:34"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"05/01/2026 09:44:38"},{"role":"client","text":"Educação Cristã Clássica","time":"05/01/2026 09:45:01"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"05/01/2026 09:45:03"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"05/01/2026 09:45:07"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"05/01/2026 09:45:39"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"05/01/2026 09:45:40"},{"role":"client","text":"Quero fazer minha matrícula","time":"05/01/2026 10:13:06"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 11:07:57"},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"05/01/2026 11:08:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"05/01/2026 11:08:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. Esse mês esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.\n\n\n🎁 Cupom de Desconto ECC: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_19\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"05/01/2026 11:08:37","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Bom dia!","time":"05/01/2026 11:22:18"},{"role":"client","text":"Tudo bem?","time":"05/01/2026 11:26:41"},{"role":"client","text":"Eu tenho um cupom de desconto do Maycon Barroco","time":"05/01/2026 11:27:02"},{"role":"client","text":"Só pra ter certeza, o curso só inicia em abril mesmo? Não tem antes?","time":"05/01/2026 11:29:10"},{"role":"agent","text":"*Thayanne Sales:* Certo, pode usar","time":"05/01/2026 11:37:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Inicia em abril o curso","time":"05/01/2026 11:37:23","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok Thayanne, muito obrigada","time":"05/01/2026 11:39:08"},{"role":"agent","text":"*Thayanne Sales:* Lhe ajudo em algo mais?","time":"05/01/2026 11:41:17","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Obrigada! Vou fazer aqui e qualquer dúvida eu chamo.","time":"05/01/2026 11:49:19"},{"role":"agent","text":"*Thayanne Sales:* Ta certo","time":"05/01/2026 11:55:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Bom dia tudo bem?","time":"06/01/2026 07:58:50"},{"role":"client","text":"Tenho algumas dúvidas","time":"06/01/2026 08:06:47"},{"role":"client","text":"Fiz minha inscrição colocando meus dados. Mas agora não está aparecendo para mim mais, a opção de anexar os documentos necessários.","time":"06/01/2026 08:07:50"},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/695cee0bb39c180c910e109a)","time":"06/01/2026 08:12:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Mandar a documentação para faculdade@cidadeviva.org","time":"06/01/2026 08:12:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Não fiz o pagamento ainda","time":"06/01/2026 08:12:47"},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/695cee7d1e76afeef004b0bc)","time":"06/01/2026 08:14:05"},{"role":"client","text":"Ok","time":"06/01/2026 08:14:56"},{"role":"client","text":"Agora apareceu inscrição não finalizada","time":"06/01/2026 08:15:11"},{"role":"client","text":"Mas não consigo fazer mais nada na página.","time":"06/01/2026 08:15:28"},{"role":"client","text":"Como faço?","time":"06/01/2026 08:15:34"},{"role":"client","text":"Estou conseguindo já","t