INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$a8e6a11e-923c-43e0-8fde-3addc9d66cd7$tag$, $tag$2026010500124$tag$, $tag$SÉRGIO SILVA MONTENEGRO (5583993552121)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom tarde! Vou passar na secretaria no dia 08/01/26, vai estar funcionando a que horas para atendimento a faculdade?","time":"05/01/2026 13:14:43"},{"role":"client","text":"🌟 Boa tarde SÉRGIO SILVA MONTENEGRO! Que alegria ter você aqui com a gente! 🙌","time":"05/01/2026 13:14:44"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"05/01/2026 13:14:47"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"05/01/2026 13:14:51"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"05/01/2026 13:14:56"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"05/01/2026 13:15:02"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"05/01/2026 13:15:07"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"05/01/2026 13:15:08"},{"role":"client","text":"Sim, concordo","time":"05/01/2026 13:17:48"},{"role":"client","text":"✅ Obrigado, SÉRGIO SILVA MONTENEGRO! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"05/01/2026 13:17:50"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"05/01/2026 13:17:54"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"05/01/2026 13:18:19"},{"role":"client","text":"Olá! SÉRGIO SILVA MONTENEGRO!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"05/01/2026 13:18:20"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"05/01/2026 13:18:24"},{"role":"client","text":"Outros assuntos","time":"05/01/2026 13:18:45"},{"role":"client","text":"Sem problemas!\n\nMe conta aqui com o que você precisa de ajuda, e vou te direcionar para o melhor caminho.\n","time":"05/01/2026 13:18:46"},{"role":"client","text":"Atendimento presencial dia 8, pode ser a que horas?","time":"05/01/2026 13:19:21"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"05/01/2026 13:58:41"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!\nHorário das 08:30 as 17:30 hrs","time":"06/01/2026 08:51:37","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nSÉRGIO SILVA MONTENEGRO, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"06/01/2026 08:51:42"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"06/01/2026 08:51:43"},{"role":"client","text":"SÉRGIO SILVA MONTENEGRO, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"06/01/2026 09:06:44"}]$tag$, $tag$2026-01-05 13:14:43+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 1, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
