INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$183f4742-dbc3-4c68-b59e-1b3b87202e77$tag$, $tag$2026010600027$tag$, $tag$Cris (5511932213657)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia!","time":"06/01/2026 09:55:58"},{"role":"client","text":"🌟 Bom dia Cris! Que alegria ter você aqui com a gente! 🙌","time":"06/01/2026 09:56:00"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"06/01/2026 09:56:04"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"06/01/2026 09:56:07"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"06/01/2026 09:56:11"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"06/01/2026 09:56:17"},{"role":"client","text":"Gostaria de saber quando o boleto para o pagamento da parcela  de janeiro será liberado?","time":"06/01/2026 09:56:20"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"06/01/2026 09:56:21"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"06/01/2026 09:56:21"},{"role":"client","text":"Sim, concordo","time":"06/01/2026 09:56:36"},{"role":"client","text":"✅ Obrigado, Cris! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"06/01/2026 09:56:37"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"06/01/2026 09:56:41"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"06/01/2026 09:57:33"},{"role":"client","text":"Olá! Cris!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"06/01/2026 09:57:34"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"06/01/2026 09:57:38"},{"role":"client","text":"Falar com um atendente","time":"06/01/2026 10:13:53"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"06/01/2026 10:13:53"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"06/01/2026 10:33:37"},{"role":"agent","text":"*Thayanne Sales:* No que posso lhe ajudar?","time":"06/01/2026 10:33:45","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"client","text":"Oi Thayanne, bom dia!","time":"06/01/2026 10:34:03"},{"role":"client","text":"Queria saber quando o boleto será liberado para pagamento.","time":"06/01/2026 10:34:19"},{"role":"client","text":"Eu ainda não recebi na minha conta do banco.","time":"06/01/2026 10:34:31"},{"role":"client","text":"Gosto de pagar antes para não correr o risco de perder o desconto.","time":"06/01/2026 10:34:47"},{"role":"agent","text":"*Thayanne Sales:* Me envia o seu nome completo, que vou verificar","time":"06/01/2026 10:37:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue